BEGIN;

-- ----------------------------------------------------------
-- Tabla: bank_balance
-- ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS "bank_balance" (
  "id" uuid DEFAULT gen_random_uuid() NOT NULL,
  "date" date NOT NULL,
  "opening_balance" numeric(10,2),
  "closing_balance" numeric(10,2),
  "notes" text,
  "created_at" timestamp DEFAULT now() NOT NULL
);


-- ----------------------------------------------------------
-- Tabla: bank_income_items
-- ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS "bank_income_items" (
  "id" uuid DEFAULT gen_random_uuid() NOT NULL,
  "date" date NOT NULL,
  "amount" numeric(10,2) NOT NULL,
  "client_id" uuid,
  "note" text,
  "created_at" timestamp DEFAULT now() NOT NULL,
  "sort_order" integer DEFAULT 0 NOT NULL
);


-- ----------------------------------------------------------
-- Tabla: budgets
-- ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS "budgets" (
  "id" uuid DEFAULT gen_random_uuid() NOT NULL,
  "category_name" text NOT NULL,
  "budget_percentage" numeric(5,2) DEFAULT 0,
  "cost_type" text DEFAULT 'variable'::text NOT NULL,
  "has_traffic_light" boolean DEFAULT true NOT NULL,
  "threshold_green" integer DEFAULT 70 NOT NULL,
  "threshold_yellow" integer DEFAULT 90 NOT NULL,
  "description" text,
  "is_active" boolean DEFAULT true NOT NULL,
  "created_at" timestamp DEFAULT now() NOT NULL,
  "updated_at" timestamp DEFAULT now() NOT NULL
);


-- ----------------------------------------------------------
-- Tabla: clients
-- ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS "clients" (
  "id" uuid DEFAULT gen_random_uuid() NOT NULL,
  "name" text NOT NULL,
  "type" text NOT NULL,
  "payment_pattern" text,
  "is_active" boolean DEFAULT true NOT NULL,
  "created_at" timestamp DEFAULT now() NOT NULL
);


-- ----------------------------------------------------------
-- Tabla: collections
-- ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS "collections" (
  "id" uuid DEFAULT gen_random_uuid() NOT NULL,
  "client_id" uuid NOT NULL,
  "date" date NOT NULL,
  "amount" numeric(10,2) NOT NULL,
  "sale_id" uuid,
  "notes" text,
  "created_at" timestamp DEFAULT now() NOT NULL
);


-- ----------------------------------------------------------
-- Tabla: daily_records
-- ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS "daily_records" (
  "id" uuid DEFAULT gen_random_uuid() NOT NULL,
  "date" date NOT NULL,
  "byte_cash" numeric(10,2) DEFAULT 0,
  "byte_credit_day" numeric(10,2) DEFAULT 0,
  "byte_credit_collected" numeric(10,2) DEFAULT 0,
  "byte_credit_balance" numeric(10,2) DEFAULT 0,
  "byte_discounts" numeric(10,2) DEFAULT 0,
  "byte_total" numeric(10,2) DEFAULT 0,
  "bank_income" numeric(10,2) DEFAULT 0,
  "bank_expense" numeric(10,2) DEFAULT 0,
  "bank_balance_real" numeric(10,2),
  "notes" text,
  "created_at" timestamp DEFAULT now() NOT NULL,
  "byte_cash_physical" numeric(10,2) DEFAULT 0,
  "byte_digital" numeric(10,2) DEFAULT 0,
  "byte_cash_sale" numeric(10,2) DEFAULT 0,
  "byte_cash_sale_method" text DEFAULT 'yape'::text
);


-- ----------------------------------------------------------
-- Tabla: expense_categories
-- ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS "expense_categories" (
  "id" uuid DEFAULT gen_random_uuid() NOT NULL,
  "name" text NOT NULL,
  "is_active" boolean DEFAULT true NOT NULL,
  "sort_order" integer DEFAULT 0 NOT NULL,
  "created_at" timestamp DEFAULT now() NOT NULL
);


-- ----------------------------------------------------------
-- Tabla: expenses
-- ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS "expenses" (
  "id" uuid DEFAULT gen_random_uuid() NOT NULL,
  "date" date NOT NULL,
  "category" text NOT NULL,
  "concept" text NOT NULL,
  "amount" numeric(10,2) NOT NULL,
  "payment_method" text DEFAULT 'transferencia'::text NOT NULL,
  "notes" text,
  "created_at" timestamp DEFAULT now() NOT NULL,
  "sort_order" integer DEFAULT 0 NOT NULL
);


-- ----------------------------------------------------------
-- Tabla: sales
-- ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS "sales" (
  "id" uuid DEFAULT gen_random_uuid() NOT NULL,
  "client_id" uuid NOT NULL,
  "date" date NOT NULL,
  "amount" numeric(10,2) NOT NULL,
  "discount" numeric(10,2) DEFAULT 0 NOT NULL,
  "net_amount" numeric(10,2) NOT NULL,
  "notes" text,
  "is_collected" boolean DEFAULT false NOT NULL,
  "created_at" timestamp DEFAULT now() NOT NULL
);


COMMIT;
